class AlgorithmImageComposeActivity : BaseComposeActivity<ThermalViewModel>() {
    override fun createViewModel(): ThermalViewModel {
        return viewModels<ThermalViewModel>().value
    }

    @OptIn(ExperimentalMaterial3Api::class)
    @Composable
    override fun Content(viewModel: ThermalViewModel) {
        var selectedAlgorithm by remember { mutableStateOf("Edge Detection") }
        var isProcessing by remember { mutableStateOf(false) }
        var processingProgress by remember { mutableFloatStateOf(0f) }
        val coroutineScope = rememberCoroutineScope()
        val snackbarHostState = remember { SnackbarHostState() }
        LibUnifiedTheme {
            Scaffold(
                topBar = {
                    TopAppBar(
                        title = {
                            Text(
                                "Algorithm Processing",
                                fontWeight = FontWeight.Bold,
                                color = Color.White
                            )
                        },
                        navigationIcon = {
                            IconButton(onClick = { finish() }) {
                                Icon(
                                    Icons.AutoMirrored.Filled.ArrowBack,
                                    contentDescription = "Back",
                                    tint = Color.White
                                )
                            }
                        },
                        actions = {
                            IconButton(onClick = {
                                coroutineScope.launch {
                                    snackbarHostState.showSnackbar("Processed result saved to gallery")
                                }
                            }) {
                                Icon(
                                    Icons.Default.Save,
                                    contentDescription = "Save",
                                    tint = Color.White
                                )
                            }
                        },
                        colors = TopAppBarDefaults.topAppBarColors(
                            containerColor = Color.Black
                        )
                    )
                },
                containerColor = Color.Black
            ) { paddingValues ->
                Column(
                    modifier = Modifier
                        .fillMaxSize()
                        .padding(paddingValues)
                        .background(Color.Black)
                ) {
                    // Image processing view
                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .weight(0.7f)
                    ) {
                        // Main image display
                        AlgorithmImageView(
                            selectedAlgorithm = selectedAlgorithm,
                            modifier = Modifier.fillMaxSize()
                        )
                        // Processing indicator
                        if (isProcessing) {
                            ProcessingOverlay(
                                progress = processingProgress,
                                modifier = Modifier.align(Alignment.Center)
                            )
                        }
                        // Algorithm info overlay
                        AlgorithmInfoOverlay(
                            selectedAlgorithm = selectedAlgorithm,
                            modifier = Modifier
                                .align(Alignment.TopStart)
                                .padding(16.dp)
                        )
                    }
                    // Control panel
                    Column(
                        modifier = Modifier
                            .fillMaxWidth()
                            .weight(0.3f)
                            .padding(16.dp),
                        verticalArrangement = Arrangement.spacedBy(16.dp)
                    ) {
                        // Algorithm selection
                        AlgorithmSelector(
                            selectedAlgorithm = selectedAlgorithm,
                            onAlgorithmSelected = { selectedAlgorithm = it }
                        )
                        // Processing controls
                        ProcessingControls(
                            isProcessing = isProcessing,
                            selectedAlgorithm = selectedAlgorithm,
                            coroutineScope = coroutineScope,
                            snackbarHostState = snackbarHostState,
                            onProcess = {
                                isProcessing = true
                                processingProgress = 0f
                                // Simulate processing
                                coroutineScope.launch {
                                    for (i in 1..100) {
                                        delay(50L)
                                        processingProgress = i / 100f
                                    }
                                    isProcessing = false
                                }
                            },
                            onStop = {
                                isProcessing = false
                                processingProgress = 0f
                            }
                        )
                    }
                }
            }
        }
    }
}

@Composable
