@Composable
private fun AlgorithmSelector(
    selectedAlgorithm: String,
    onAlgorithmSelected: (String) -> Unit
) {
    val algorithms = getAlgorithmOptions()
    Card(
        colors = CardDefaults.cardColors(
            containerColor = Color(0xFF21262D)
        ),
        shape = RoundedCornerShape(12.dp)
    ) {
        Column(
            modifier = Modifier
                .fillMaxWidth()
                .padding(16.dp)
        ) {
            Text(
                "Algorithm Selection",
                color = Color.White,
                fontSize = 14.sp,
                fontWeight = FontWeight.Bold
            )
            Spacer(modifier = Modifier.height(12.dp))
            LazyRow(
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                items(algorithms) { algorithm ->
                    AlgorithmChip(
                        algorithm = algorithm,
                        isSelected = selectedAlgorithm == algorithm.name,
                        onClick = { onAlgorithmSelected(algorithm.name) }
                    )
                }
            }
        }
    }
}

@Composable
private fun AlgorithmChip(
    algorithm: AlgorithmOption,
    isSelected: Boolean,
    onClick: () -> Unit
) {
    FilterChip(
        onClick = onClick,
        label = {
            Text(
                algorithm.name,
                fontSize = 12.sp
            )
        },
        selected = isSelected,
