@Composable
private fun ProcessingControls(
    isProcessing: Boolean,
    selectedAlgorithm: String,
    coroutineScope: kotlinx.coroutines.CoroutineScope,
    snackbarHostState: SnackbarHostState,
    onProcess: () -> Unit,
