import com.mpdc4gsr.module.thermalunified.viewmodel.ThermalViewModel

class BaseIRComposeActivity : BaseComposeActivity<ThermalViewModel>() {
    override fun createViewModel(): ThermalViewModel {
        return viewModels<ThermalViewModel>().value
    }

    @OptIn(ExperimentalMaterial3Api::class)
    @Composable
    override fun Content(viewModel: ThermalViewModel) {
        var connectionStatus by remember { mutableStateOf("Disconnected") }
        var cameraReady by remember { mutableStateOf(false) }
        var thermalMode by remember { mutableIntStateOf(1) }
        LibUnifiedTheme {
            Scaffold(
                topBar = {
                    TopAppBar(
                        title = {
                            Text(
                                "Thermal Base Control",
                                fontWeight = FontWeight.Bold,
                                color = Color.White
                            )
                        },
                        navigationIcon = {
                            IconButton(onClick = { finish() }) {
                                Icon(
                                    Icons.AutoMirrored.Filled.ArrowBack,
                                    contentDescription = "Back",
                                    tint = Color.White
                                )
                            }
                        },
                        actions = {
                            IconButton(onClick = {
                                // TODO: Open thermal camera settings
                                android.widget.Toast.makeText(
                                    this@BaseIRComposeActivity,
                                    "Opening settings...",
                                    android.widget.Toast.LENGTH_SHORT
                                ).show()
                            }) {
                                Icon(
                                    Icons.Default.Settings,
                                    contentDescription = "Settings",
                                    tint = Color.White
                                )
                            }
                        },
                        colors = TopAppBarDefaults.topAppBarColors(
                            containerColor = Color.Black
                        )
                    )
                },
                containerColor = Color.Black
            ) { paddingValues ->
                Column(
                    modifier = Modifier
                        .fillMaxSize()
                        .padding(paddingValues)
                        .background(Color.Black)
                ) {
                    // Status bar
                    ThermalStatusBar(
                        connectionStatus = connectionStatus,
                        cameraReady = cameraReady,
                        modifier = Modifier.fillMaxWidth()
                    )
                    // Main thermal view
                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .weight(1f)
                    ) {
                        // Thermal camera surface
                        ThermalCameraSurface(
                            modifier = Modifier.fillMaxSize()
                        )
                        // Control overlay
                        ThermalControlOverlay(
                            thermalMode = thermalMode,
                            onModeChange = { thermalMode = it },
                            modifier = Modifier
                                .align(Alignment.BottomCenter)
                                .fillMaxWidth()
                        )
                    }
                }
            }
        }
        // Initialize camera connection
        LaunchedEffect(Unit) {
            kotlinx.coroutines.delay(2000L)
            connectionStatus = "Connected"
            cameraReady = true
        }
    }
}

@Composable
private fun ThermalStatusBar(
    connectionStatus: String,
