class ConnectComposeActivity : BaseComposeActivity<ThermalViewModel>() {
    override fun createViewModel(): ThermalViewModel {
        return viewModels<ThermalViewModel>().value
    }

    @OptIn(ExperimentalMaterial3Api::class)
    @Composable
    override fun Content(viewModel: ThermalViewModel) {
        var isConnected by remember { mutableStateOf(DeviceTools.isConnect()) }
        var isConnecting by remember { mutableStateOf(false) }
        val coroutineScope = rememberCoroutineScope()
        LibUnifiedTheme {
            Scaffold(
                topBar = {
                    TopAppBar(
                        title = {
                            Text(
                                "Device Connection",
                                fontWeight = FontWeight.Bold,
                                color = Color.White
                            )
                        },
                        navigationIcon = {
                            IconButton(onClick = { finish() }) {
                                Icon(
                                    Icons.AutoMirrored.Filled.ArrowBack,
                                    contentDescription = "Back",
                                    tint = Color.White
                                )
                            }
                        },
                        colors = TopAppBarDefaults.topAppBarColors(
                            containerColor = Color.Black
                        )
                    )
                },
                containerColor = Color.Black
            ) { paddingValues ->
                Column(
                    modifier = Modifier
                        .fillMaxSize()
                        .padding(paddingValues)
                        .background(Color.Black)
                        .padding(16.dp),
                    verticalArrangement = Arrangement.Center,
                    horizontalAlignment = Alignment.CenterHorizontally
                ) {
                    // Connection Status Card
                    ConnectionStatusCard(
                        isConnected = isConnected,
                        isConnecting = isConnecting,
                        modifier = Modifier.fillMaxWidth()
                    )
                    Spacer(modifier = Modifier.height(32.dp))
                    // Connection Controls
                    ConnectionControls(
                        isConnected = isConnected,
                        isConnecting = isConnecting,
                        onConnect = {
                            isConnecting = true
                            // Simulate connection process
                            coroutineScope.launch {
                                delay(2000L)
                                isConnected = true
                                isConnecting = false
                            }
                        },
                        onDisconnect = {
                            isConnected = false
                            isConnecting = false
                        }
                    )
                    Spacer(modifier = Modifier.height(24.dp))
                    // Device Information
                    if (isConnected) {
                        DeviceInfoCard(
                            modifier = Modifier.fillMaxWidth()
                        )
                    }
                }
            }
        }
    }
}

@Composable
private fun ConnectionStatusCard(
    isConnected: Boolean,
    isConnecting: Boolean,
    modifier: Modifier = Modifier
) {
    Card(
        modifier = modifier,
        colors = CardDefaults.cardColors(
            containerColor = Color(0xFF21262D)
        ),
        shape = RoundedCornerShape(12.dp)
    ) {
        Column(
            modifier = Modifier
                .fillMaxWidth()
                .padding(24.dp),
            horizontalAlignment = Alignment.CenterHorizontally
        ) {
            // Status Icon
            when {
                isConnecting -> {
                    CircularProgressIndicator(
                        color = Color(0xFFFF6B35),
                        modifier = Modifier.size(48.dp)
                    )
                }

                isConnected -> {
                    Icon(
                        Icons.Default.CheckCircle,
                        contentDescription = "Connected",
                        tint = Color(0xFF00FF00),
                        modifier = Modifier.size(48.dp)
                    )
                }

                else -> {
                    Icon(
                        Icons.Default.Error,
                        contentDescription = "Disconnected",
                        tint = Color(0xFFFF4444),
                        modifier = Modifier.size(48.dp)
                    )
                }
            }
            Spacer(modifier = Modifier.height(16.dp))
            // Status Text
            Text(
                when {
                    isConnecting -> "Connecting..."
                    isConnected -> "Device Connected"
                    else -> "Device Disconnected"
                },
                color = Color.White,
                fontSize = 18.sp,
                fontWeight = FontWeight.Bold
            )
            Spacer(modifier = Modifier.height(8.dp))
            Text(
                when {
                    isConnecting -> "Establishing connection to thermal camera"
                    isConnected -> "Thermal camera is ready for use"
                    else -> "Please connect your thermal camera device"
                },
                color = Color(0xFF7D8590),
                fontSize = 14.sp
            )
        }
    }
}

@Composable
private fun ConnectionControls(
    isConnected: Boolean,
    isConnecting: Boolean,
    onConnect: () -> Unit,
    onDisconnect: () -> Unit
) {
    Row(
        horizontalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        if (!isConnected && !isConnecting) {
            Button(
                onClick = onConnect,
                colors = ButtonDefaults.buttonColors(
                    containerColor = Color(0xFFFF6B35)
                ),
                shape = RoundedCornerShape(12.dp),
                modifier = Modifier
                    .weight(1f)
                    .height(56.dp)
            ) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    Icon(
                        Icons.Default.Bluetooth,
                        contentDescription = "Connect",
