    // Embed existing video fragment using AndroidView wrapper
    AndroidView(
        factory = { context ->
            androidx.fragment.app.FragmentContainerView(context).apply {
                id = androidx.core.R.id.accessibility_custom_action_1
            }
        },
        modifier = Modifier.fillMaxSize()
    )
}


