                                onValueChange = { temperatureUnit = it }
                            )
                        }
                    }
                    // Advanced Settings
                    item {
                        SettingsCategoryCard(
                            title = "Advanced Settings",
                            icon = Icons.Default.Tune
                        ) {
                            AdvancedSettingItem(
