                                    android.widget.Toast.LENGTH_SHORT
                                ).show()
                            },
                            onReset = {
                                // TODO: Reset settings to defaults
                                selectedPalette = "Iron"
                                frameRate = 9
                                autoShutter = true
                                imageCorrection = true
                                temperatureUnit = "Celsius"
                                resolution = "384x288"
