) {
    // Embed existing gallery fragment using AndroidView
    AndroidView(
        factory = { context ->
            val fragment = GalleryComposeFragment()
            androidx.fragment.app.FragmentContainerView(context).apply {
                id = androidx.core.R.id.accessibility_custom_action_2
            }
