                Icon(
                    Icons.Default.Thermostat,
                    contentDescription = "Thermal Image",
                    tint = Color(0xFFFF6B35),
                    modifier = Modifier.size(32.dp)
                )
            }
            Spacer(modifier = Modifier.height(8.dp))
            // Image info
            Text(
                image.name,
                color = Color.White,
                fontSize = 12.sp,
                fontWeight = FontWeight.Medium,
                maxLines = 1
            )
            Text(
                "${image.temperature}Â°C",
                color = Color(0xFFFF6B35),
                fontSize = 10.sp
            )
            Text(
                image.date,
                color = Color(0xFF7D8590),
                fontSize = 10.sp
            )
        }
    }
}

@Composable
private fun ThermalImageListItem(
    image: GalleryThermalImage,
    onMoreClick: () -> Unit = {}
) {
    Card(
        modifier = Modifier.fillMaxWidth(),
        colors = CardDefaults.cardColors(containerColor = Color(0xFF21262D)),
        shape = RoundedCornerShape(8.dp)
    ) {
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(12.dp),
            verticalAlignment = Alignment.CenterVertically
        ) {
            // Thumbnail
            Box(
                modifier = Modifier
                    .size(60.dp)
                    .background(
                        Color(0xFF0D1117),
                        RoundedCornerShape(6.dp)
                    ),
                contentAlignment = Alignment.Center
            ) {
                Icon(
                    Icons.Default.Thermostat,
                    contentDescription = "Thermal Image",
                    tint = Color(0xFFFF6B35),
                    modifier = Modifier.size(24.dp)
                )
            }
            Spacer(modifier = Modifier.width(12.dp))
            // Image details
            Column(
                modifier = Modifier.weight(1f)
            ) {
                Text(
                    image.name,
                    color = Color.White,
                    fontSize = 14.sp,
                    fontWeight = FontWeight.Medium
                )
                Text(
                    "${image.temperature}Â°C â€¢ ${image.date}",
                    color = Color(0xFF7D8590),
                    fontSize = 12.sp
                )
                Text(
                    "${image.resolution} â€¢ ${image.size}",
                    color = Color(0xFF7D8590),
                    fontSize = 10.sp
                )
            }
            // Actions
            IconButton(onClick = onMoreClick) {
                Icon(
                    Icons.Default.MoreVert,
                    contentDescription = "More",
                    tint = Color(0xFF7D8590)
                )
            }
        }
    }
}

private fun generateSampleThermalImages(): List<GalleryThermalImage> {
    return (1..20).map { index ->
        GalleryThermalImage(
            id = index,
            name = "thermal_image_$index.tiff",
            temperature = (20..80).random(),
            date = "2024-01-${(10..28).random()}",
            resolution = "640x480",
            size = "${(100..500).random()}KB"
        )
    }
}

private data class GalleryThermalImage(
    val id: Int,
    val name: String,
    val temperature: Int,
    val date: String,
    val resolution: String,
    val size: String
)

private enum class ViewMode {
    GRID, LIST
}

private enum class FilterType(val displayName: String) {
    ALL("All"),
    TODAY("Today"),
    THIS_WEEK("This Week"),
    HIGH_TEMP("High Temp"),
    LOW_TEMP("Low Temp")
}


