@Composable
fun ChartLogCompose(
    thermalData: List<ThermalDataEntry>,
    chartType: ThermalChartType = ThermalChartType.POINT,
    timeFormat: TimeFormat = TimeFormat.HOURS,
    showGrid: Boolean = true,
    showLegend: Boolean = true,
    modifier: Modifier = Modifier
) {
    val density = LocalDensity.current
    Card(
        modifier = modifier,
        elevation = CardDefaults.cardElevation(defaultElevation = 4.dp),
        shape = RoundedCornerShape(8.dp)
    ) {
        Column(
            modifier = Modifier.padding(16.dp)
        ) {
            // Chart header
            ChartHeader(
                title = "Thermal Log Chart",
                chartType = chartType,
                dataCount = thermalData.size
            )
            Spacer(modifier = Modifier.height(16.dp))
            // Chart area
            if (thermalData.isEmpty()) {
                EmptyChartState(
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(300.dp)
                )
            } else {
                Canvas(
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(300.dp)
                ) {
                    drawThermalChart(
                        data = thermalData,
                        chartType = chartType,
                        timeFormat = timeFormat,
                        showGrid = showGrid
                    )
                }
                if (showLegend) {
                    Spacer(modifier = Modifier.height(8.dp))
                    ChartLegend(chartType = chartType)
                }
            }
        }
    }
}

@Composable
