@Composable
fun ConfigGuideDialogCompose(
    isTC007: Boolean,
    initialStep: Int = 1,
    onDismiss: () -> Unit,
    onComplete: () -> Unit = {}
) {
    var currentStep by remember(initialStep) { mutableIntStateOf(initialStep) }
    Dialog(
        onDismissRequest = onDismiss,
        properties = DialogProperties(
            dismissOnBackPress = false,
            dismissOnClickOutside = false,
            usePlatformDefaultWidth = false
        )
    ) {
        Box(
            modifier = Modifier
                .fillMaxSize()
                .background(Color.Black.copy(alpha = 0.7f))
                .blur(8.dp),
            contentAlignment = Alignment.Center
        ) {
            AnimatedContent(
                targetState = currentStep,
                transitionSpec = {
                    slideInHorizontally(
                        animationSpec = tween(300),
                        initialOffsetX = { if (targetState > initialState) 300 else -300 }
                    ) + fadeIn() togetherWith
                            slideOutHorizontally(
                                animationSpec = tween(300),
                                targetOffsetX = { if (targetState > initialState) -300 else 300 }
                            ) + fadeOut()
                },
                label = "config_step"
            ) { step ->
                when (step) {
                    1 -> ConfigStep1Content(
                        isTC007 = isTC007,
                        onNext = { currentStep = 2 }
                    )

                    2 -> ConfigStep2Content(
                        isTC007 = isTC007,
                        onComplete = {
                            onComplete()
                            onDismiss()
                        }
                    )
                }
            }
        }
    }
}

