@Composable
fun HomeGuideDialogCompose(
    initialStep: Int = 1,
    onNextStep: (step: Int) -> Unit = {},
    onSkinClick: () -> Unit = {},
    onDismiss: () -> Unit
) {
    var currentStep by remember(initialStep) { mutableIntStateOf(initialStep) }
    Dialog(
        onDismissRequest = onDismiss,
        properties = DialogProperties(
            dismissOnBackPress = true,
            dismissOnClickOutside = false,
            usePlatformDefaultWidth = false
        )
    ) {
        Box(
            modifier = Modifier
                .fillMaxSize()
                .background(Color.Black.copy(alpha = 0.6f))
                .blur(8.dp),
            contentAlignment = Alignment.Center
        ) {
            AnimatedContent(
                targetState = currentStep,
                transitionSpec = {
                    slideInHorizontally(
                        animationSpec = tween(300),
                        initialOffsetX = { if (targetState > initialState) 300 else -300 }
                    ) + fadeIn() togetherWith
                            slideOutHorizontally(
                                animationSpec = tween(300),
                                targetOffsetX = { if (targetState > initialState) -300 else 300 }
                            ) + fadeOut()
                },
                label = "guide_step"
            ) { step ->
                GuideStepContent(
                    step = step,
                    onNext = {
                        when (step) {
                            1 -> {
                                currentStep = 2
                                onNextStep(1)
                            }

                            2 -> {
                                currentStep = 3
                                onNextStep(2)
                            }

                            3 -> {
                                onNextStep(3)
                                onDismiss()
                            }
                        }
                    },
                    onSkinClick = {
                        onSkinClick()
                        onDismiss()
                    }
                )
            }
        }
    }
}

@Composable
private fun GuideStepContent(
    step: Int,
    onNext: () -> Unit,
    onSkinClick: () -> Unit
) {
    Card(
        modifier = Modifier
            .fillMaxWidth(0.85f)
            .wrapContentHeight(),
        elevation = CardDefaults.cardElevation(defaultElevation = 8.dp),
        shape = RoundedCornerShape(16.dp)
    ) {
        Column(
            modifier = Modifier.padding(24.dp),
            horizontalAlignment = Alignment.CenterHorizontally
        ) {
            when (step) {
                1 -> GuideStep1Content(onNext, onSkinClick)
                2 -> GuideStep2Content(onNext, onSkinClick)
                3 -> GuideStep3Content(onNext)
            }
        }
    }
}

