                        Icon(
                            imageVector = tempMode.icon,
                            contentDescription = null,
                            modifier = Modifier.size(16.dp)
                        )
                    }
                )
            }
        }
        // Temperature edit interface
        TemperatureEditCompose(
            mode = mode,
            isShowName = true,
