@Composable
fun TrendViewCompose(
    temperatureData: List<Float>,
    isExpanded: Boolean = false,
    onExpandToggle: () -> Unit = {},
    modifier: Modifier = Modifier
) {
    Card(
        modifier = modifier.fillMaxWidth(),
