@Composable
private fun VideoControlsOverlayCompose(
    isPlaying: Boolean,
    isLoading: Boolean,
    isFullscreen: Boolean,
    currentPosition: Long,
    duration: Long,
    volume: Float,
    title: String?,
    onPlayPause: () -> Unit,
    onSeek: (Long) -> Unit,
    onVolumeChange: (Float) -> Unit,
    onFullscreenToggle: () -> Unit,
    modifier: Modifier = Modifier
) {
    var showControls by remember { mutableStateOf(true) }
    var showVolumeSlider by remember { mutableStateOf(false) }
    LaunchedEffect(showControls) {
        if (showControls && isPlaying) {
            // Auto-hide controls after 3 seconds when playing
            kotlinx.coroutines.delay(3000)
            showControls = false
        }
    }
    Box(
        modifier = modifier.clickable { showControls = !showControls }
    ) {
        AnimatedVisibility(
            visible = showControls,
            enter = fadeIn(animationSpec = tween(300)),
            exit = fadeOut(animationSpec = tween(300))
        ) {
            // Top bar with title and fullscreen
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(
                        Color.Black.copy(alpha = 0.6f)
                    )
                    .padding(16.dp),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Text(
                    text = title ?: "Video",
                    style = MaterialTheme.typography.titleMedium,
                    color = Color.White,
                    modifier = Modifier.weight(1f)
                )
                IconButton(
                    onClick = onFullscreenToggle
                ) {
                    Icon(
                        imageVector = if (isFullscreen) Icons.Default.FullscreenExit else Icons.Default.Fullscreen,
                        contentDescription = "Toggle fullscreen",
                        tint = Color.White
                    )
                }
            }
        }
        // Center play/pause button
        AnimatedVisibility(
            visible = showControls && !isLoading,
            enter = scaleIn(animationSpec = spring(dampingRatio = Spring.DampingRatioMediumBouncy)),
            exit = scaleOut(animationSpec = tween(200)),
            modifier = Modifier.align(Alignment.Center)
        ) {
            FloatingActionButton(
                onClick = onPlayPause,
                modifier = Modifier.size(72.dp),
                containerColor = MaterialTheme.colorScheme.primary.copy(alpha = 0.9f)
            ) {
                Icon(
                    imageVector = if (isPlaying) Icons.Default.Pause else Icons.Default.PlayArrow,
                    contentDescription = if (isPlaying) "Pause" else "Play",
                    modifier = Modifier.size(36.dp),
                    tint = Color.White
                )
            }
        }
        // Bottom controls
        AnimatedVisibility(
            visible = showControls,
            enter = slideInVertically(
                initialOffsetY = { it },
                animationSpec = tween(300)
            ) + fadeIn(),
            exit = slideOutVertically(
                targetOffsetY = { it },
                animationSpec = tween(300)
            ) + fadeOut(),
            modifier = Modifier.align(Alignment.BottomCenter)
        ) {
            VideoBottomControlsCompose(
                currentPosition = currentPosition,
                duration = duration,
                volume = volume,
                showVolumeSlider = showVolumeSlider,
                onSeek = onSeek,
                onVolumeChange = onVolumeChange,
                onVolumeToggle = { showVolumeSlider = !showVolumeSlider }
            )
        }
    }
}

@Composable
private fun VideoBottomControlsCompose(
    currentPosition: Long,
    duration: Long,
    volume: Float,
    showVolumeSlider: Boolean,
    onSeek: (Long) -> Unit,
    onVolumeChange: (Float) -> Unit,
    onVolumeToggle: () -> Unit
) {
    Column(
        modifier = Modifier
            .fillMaxWidth()
            .background(
                Color.Black.copy(alpha = 0.6f)
            )
            .padding(16.dp)
    ) {
        // Progress bar
        Row(
            modifier = Modifier.fillMaxWidth(),
            verticalAlignment = Alignment.CenterVertically
        ) {
            Text(
                text = formatTime(currentPosition),
                style = MaterialTheme.typography.bodySmall,
                color = Color.White,
                modifier = Modifier.width(48.dp)
            )
            Slider(
                value = if (duration > 0) currentPosition.toFloat() / duration else 0f,
                onValueChange = { progress ->
                    onSeek((progress * duration).toLong())
                },
                modifier = Modifier.weight(1f),
                colors = SliderDefaults.colors(
                    thumbColor = MaterialTheme.colorScheme.primary,
                    activeTrackColor = MaterialTheme.colorScheme.primary,
                    inactiveTrackColor = Color.White.copy(alpha = 0.3f)
                )
            )
            Text(
                text = formatTime(duration),
                style = MaterialTheme.typography.bodySmall,
                color = Color.White,
                modifier = Modifier.width(48.dp),
                textAlign = TextAlign.End
            )
        }
        // Volume controls
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.End,
            verticalAlignment = Alignment.CenterVertically
        ) {
            AnimatedVisibility(
                visible = showVolumeSlider,
                enter = slideInHorizontally(initialOffsetX = { it }) + fadeIn(),
                exit = slideOutHorizontally(targetOffsetX = { it }) + fadeOut()
            ) {
                Row(
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Slider(
                        value = volume,
                        onValueChange = onVolumeChange,
                        modifier = Modifier.width(100.dp),
                        colors = SliderDefaults.colors(
                            thumbColor = MaterialTheme.colorScheme.primary,
                            activeTrackColor = MaterialTheme.colorScheme.primary,
                            inactiveTrackColor = Color.White.copy(alpha = 0.3f)
                        )
                    )
                    Spacer(modifier = Modifier.width(8.dp))
                }
            }
            IconButton(
                onClick = onVolumeToggle
            ) {
                Icon(
                    imageVector = when {
                        volume == 0f -> Icons.AutoMirrored.Filled.VolumeOff
                        volume < 0.5f -> Icons.AutoMirrored.Filled.VolumeDown
                        else -> Icons.AutoMirrored.Filled.VolumeUp
                    },
                    contentDescription = "Volume",
                    tint = Color.White
                )
            }
        }
    }
}

@Composable
fun ThermalImageLoaderCompose(
    url: String?,
    contentDescription: String? = null,
    placeholderIcon: ImageVector = Icons.Default.Image,
    errorIcon: ImageVector = Icons.Default.BrokenImage,
    modifier: Modifier = Modifier,
