            )
            // Monitoring status and alerts
            MonitoringStatusSection(
                isConnected = uiState.isDeviceConnected,
                isRecording = uiState.isRecording,
                alertCount = uiState.alertCount
            )
        }
    }

    @Composable
    private fun ThermalCameraSection(
