package com.mpdc4gsr.module.thermalunified.report.viewmodel

import androidx.lifecycle.viewModelScope
import com.elvishew.xlog.XLog
import com.google.gson.Gson
import com.mpdc4gsr.libunified.app.ktbase.BaseViewModel
import com.mpdc4gsr.libunified.app.lms.LMS
import com.mpdc4gsr.libunified.app.lms.UrlConstants
import com.mpdc4gsr.libunified.app.lms.bean.CommonBean
import com.mpdc4gsr.libunified.app.lms.network.HttpProxy
import com.mpdc4gsr.libunified.app.lms.network.IResponseCallback
import com.mpdc4gsr.libunified.app.lms.network.ResponseBean
import com.mpdc4gsr.libunified.app.lms.xutils.http.RequestParams
import com.mpdc4gsr.libunified.app.utils.SingleLiveEvent
import com.mpdc4gsr.module.thermalunified.report.bean.ReportBean
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch
import kotlinx.coroutines.withContext
import org.json.JSONObject
import java.io.File
import java.text.SimpleDateFormat
import java.util.Date
import java.util.Locale
import java.util.concurrent.CountDownLatch

class UpReportViewModel : BaseViewModel() {
    val commonBeanLD = SingleLiveEvent<CommonBean>()
    val exceptionLD = SingleLiveEvent<Exception?>()
    private val gson = Gson()
    private val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss", Locale.getDefault())
    fun upload(
        isTC007: Boolean,
        reportBean: ReportBean?,
    ) {
        viewModelScope.launch {
            uploadImages(reportBean)
            uploadJSON(isTC007, reportBean)
        }
    }

    private suspend fun uploadImages(reportBean: ReportBean?) {
        withContext(Dispatchers.IO) {
            val irList = reportBean?.infrared_data
            if (irList != null) {
                val downLatch = CountDownLatch(irList.size)
                for (reportIrBean in irList) {
                    if (reportIrBean.picture_id.isNotEmpty()) {
                        downLatch.countDown()
                        continue
                    }
                    val file = File(reportIrBean.picture_url)
                    LMS.getInstance().uploadFile(file, 0, 13, 20) { response ->
                        try {
                            if (response != null) {
                                val jsonObject = JSONObject(response)
                                val code = jsonObject.optString("code", "")
                                if (code == LMS.SUCCESS) {
                                    file.delete()
                                    val dataObject = jsonObject.optJSONObject("data")
                                    if (dataObject != null) {
                                        reportIrBean.picture_id =
                                            dataObject.optString("fileSecret", "")
                                        reportIrBean.picture_url = dataObject.optString("url", "")
                                    }
                                }
                            }
                        } catch (e: Exception) {
                            XLog.e("Error parsing upload response", e)
                        }
                        XLog.i("Upload")
                        downLatch.countDown()
                    }
                }
                downLatch.await()
                XLog.i("${irList.size} Upload")
            }
        }
    }

    private suspend fun uploadJSON(
        isTC007: Boolean,
        reportBean: ReportBean?,
    ) {
        withContext(Dispatchers.IO) {
            val url = UrlConstants.BASE_URL + "api/v1/outProduce/testReport/addTestReport"
            val params = RequestParams()
            params.addBodyParameter("reportType", 2)
            params.addBodyParameter(
                "modelId",
                if (isTC007) 1783 else 950
            )
            params.addBodyParameter("testTime", dateFormat.format(Date()))
            params.addBodyParameter("testInfo", gson.toJson(reportBean))
            params.addBodyParameter("sn", "")
            HttpProxy.getInstant().post(
                url,
                params,
                object : IResponseCallback {
                    override fun onResponse(response: String?) {
                        commonBeanLD.postValue(ResponseBean.convertCommonBean(response, null))
                    }

                    override fun onFail(exception: Exception?) {
                        exceptionLD.postValue(exception)
                    }
                },
            )
        }
    }
}


// ===== component\thermalunified\src\main\java\com\mpdc4gsr\module\thermalunified\repository\ConfigRepository.kt =====

package com.mpdc4gsr.module.thermalunified.repository

import com.google.gson.Gson
import com.mpdc4gsr.libunified.app.common.SharedManager
import com.mpdc4gsr.module.thermalunified.bean.DataBean
import com.mpdc4gsr.module.thermalunified.bean.ModelBean

object ConfigRepository {
    fun read(isTC007: Boolean): ModelBean =
        try {
            // TC007 functionality removed
            Gson().fromJson(
                if (isTC007) "{}" else SharedManager.getIRConfig(), // Use empty JSON for TC007
                ModelBean::class.java
            )
        } catch (_: Exception) {
            ModelBean(DataBean(id = 0, use = true))
        }

    fun update(
        isTC007: Boolean,
        bean: ModelBean,
    ) {
        if (isTC007) {
            // TC007 functionality removed - do nothing
        } else {
            SharedManager.setIRConfig(Gson().toJson(bean))
        }
    }

    fun readConfig(isTC007: Boolean): DataBean {
        val config = read(isTC007)
        if (config.defaultModel.use) {
            return config.defaultModel
        }
        config.myselfModel.forEach {
            if (it.use) {
                return it
            }
        }
        return config.defaultModel
    }
}


// ===== component\thermalunified\src\main\java\com\mpdc4gsr\module\thermalunified\repository\ThermalDataRepository.kt =====

package com.mpdc4gsr.module.thermalunified.repository

import com.mpdc4gsr.libunified.app.repository.BaseRepository
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.delay
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.flow
import kotlinx.coroutines.flow.flowOn

class ThermalDataRepository : BaseRepository() {
    data class ThermalReading(
        val timestamp: Long,
        val temperature: Float,
        val x: Int,
        val y: Int,
        val deviceId: String,
        val quality: ReadingQuality = ReadingQuality.GOOD
    )

    enum class ReadingQuality { EXCELLENT, GOOD, FAIR, POOR, INVALID }
    data class ThermalFrameData(
        val frameId: String,
        val timestamp: Long,
        val width: Int,
        val height: Int,
        val readings: List<ThermalReading>,
        val metadata: FrameMetadata
    )

    data class FrameMetadata(
        val deviceType: String,
        val calibrationData: String,
        val ambientTemperature: Float,
        val frameRate: Int
    )

    // Real-time thermal data stream
    fun getThermalDataStream(deviceId: String): Flow<BaseRepository.Result<ThermalFrameData>> =
        flow {
            emit(BaseRepository.Result.Loading)
            try {
                while (true) {
                    delay(100) // 10 FPS simulation
                    val frame = generateThermalFrame(deviceId)
                    emit(BaseRepository.Result.Success(frame))
                }
            } catch (e: Exception) {
                emit(BaseRepository.Result.Error(e))
            }
        }.flowOn(Dispatchers.IO)

    // Historical thermal data with caching
    fun getHistoricalThermalData(
        deviceId: String,
        startTime: Long,
        endTime: Long
    ): Flow<BaseRepository.Result<List<ThermalFrameData>>> = safeFlow {
        val cacheKey = "thermal_${deviceId}_${startTime}_${endTime}"
        val ttlMs = 300000L // 5 minutes TTL
        val data = getCachedOrExecute<List<ThermalFrameData>>(cacheKey, ttlMs) {
            delay(1500) // Simulate data loading
            generateHistoricalData(deviceId, startTime, endTime)
        }
        data
    }

    private fun generateThermalFrame(deviceId: String): ThermalFrameData {
        val timestamp = System.currentTimeMillis()
        val readings = mutableListOf<ThermalReading>()
        // Generate sample thermal readings for a 32x24 array
        for (y in 0 until 24) {
            for (x in 0 until 32) {
                val baseTemp = 25.0f
                val variation = (Math.sin(x * 0.2) * Math.cos(y * 0.3) * 10).toFloat()
                val noise = (Math.random() * 2 - 1).toFloat()
                readings.add(
                    ThermalReading(
                        timestamp = timestamp,
                        temperature = baseTemp + variation + noise,
                        x = x,
                        y = y,
                        deviceId = deviceId,
                        quality = if (Math.random() < 0.95) ReadingQuality.GOOD else ReadingQuality.FAIR
                    )
                )
            }
        }
        return ThermalFrameData(
            frameId = "frame_${timestamp}",
            timestamp = timestamp,
            width = 32,
            height = 24,
            readings = readings,
            metadata = FrameMetadata(
                deviceType = "TC007",
                calibrationData = "cal_${deviceId}",
                ambientTemperature = 22.5f,
                frameRate = 10
            )
        )
    }

    private fun generateHistoricalData(
        deviceId: String,
        startTime: Long,
        endTime: Long
    ): List<ThermalFrameData> {
        val frames = mutableListOf<ThermalFrameData>()
        val interval = 1000L // 1 second intervals
        var currentTime = startTime
        while (currentTime <= endTime) {
            frames.add(generateThermalFrame(deviceId).copy(timestamp = currentTime))
            currentTime += interval
        }
        return frames
    }
}


